// Calculate funnel metrics
const orders = $input.all()[0]?.json || [];
const ga4Data = $input.all()[1]?.json?.rows || [];

// Aggregate GA4 data
const totalSessions = ga4Data.reduce((sum, row) => sum + parseInt(row.metricValues?.[0]?.value || 0), 0);
const totalPageViews = ga4Data.reduce((sum, row) => sum + parseInt(row.metricValues?.[1]?.value || 0), 0);
const totalAddToCarts = ga4Data.reduce((sum, row) => sum + parseInt(row.metricValues?.[2]?.value || 0), 0);
const totalCheckouts = ga4Data.reduce((sum, row) => sum + parseInt(row.metricValues?.[3]?.value || 0), 0);
const totalPurchases = orders.length;

// Calculate conversion rates
const awarenessToInterest = totalSessions > 0 ? ((totalPageViews / totalSessions) * 100).toFixed(2) : 0;
const interestToConsideration = totalPageViews > 0 ? ((totalAddToCarts / totalPageViews) * 100).toFixed(2) : 0;
const considerationToConversion = totalAddToCarts > 0 ? ((totalCheckouts / totalAddToCarts) * 100).toFixed(2) : 0;
const conversionToPurchase = totalCheckouts > 0 ? ((totalPurchases / totalCheckouts) * 100).toFixed(2) : 0;
const overallConversion = totalSessions > 0 ? ((totalPurchases / totalSessions) * 100).toFixed(2) : 0;

// Identify drop-off points
const dropoffs = [];
if (awarenessToInterest < 50) dropoffs.push({ stage: 'Awareness → Interest', rate: awarenessToInterest + '%' });
if (interestToConsideration < 10) dropoffs.push({ stage: 'Interest → Consideration', rate: interestToConsideration + '%' });
if (considerationToConversion < 30) dropoffs.push({ stage: 'Consideration → Conversion', rate: considerationToConversion + '%' });
if (conversionToPurchase < 60) dropoffs.push({ stage: 'Conversion → Purchase', rate: conversionToPurchase + '%' });

// Revenue attribution
const revenueByChannel = {};
orders.forEach(order => {
  const source = order.source_name || 'direct';
  if (!revenueByChannel[source]) revenueByChannel[source] = 0;
  revenueByChannel[source] += parseFloat(order.total_price || 0);
});

return [{
  json: {
    date_range: 'Last 7 days',
    funnel: {
      awareness: { sessions: totalSessions },
      interest: { page_views: totalPageViews, conversion_rate: awarenessToInterest },
      consideration: { add_to_carts: totalAddToCarts, conversion_rate: interestToConsideration },
      conversion: { checkouts: totalCheckouts, conversion_rate: considerationToConversion },
      purchase: { orders: totalPurchases, conversion_rate: conversionToPurchase }
    },
    overall_conversion_rate: overallConversion,
    dropoff_points: dropoffs,
    revenue_by_channel: revenueByChannel,
    generated_at: new Date().toISOString()
  }
}];

